onClick:
{{
(() => {

  const questions = List_Questions.listData || [];

  const invalid = questions.some(q => {

    const ans = appsmith.store.answers?.[q.id];

    // ❗ skip completely untouched questions
    if (!ans || ans.YesNo === undefined) return false;

    // 🚀 ONLY validate when NO
    if (Number(ans.YesNo) === 0) {

      const responsible = ans.ResponsiblePerson;
      const action = ans.Action;
      const due = ans.DueDate;

      return (
        !responsible || responsible.toString().trim() === "" ||
        !action || action.toString().trim() === "" ||
        !due || due.toString().trim() === ""
      );

    }

    return false;

  });

  if (invalid) {
    showAlert("All 'No' answers must have Responsible Person, Action and Due Date", "error");
    return;
  }

  const versionId = "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === "x" ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });

  return storeValue("currentVersion", versionId)
    .then(() => InsertAnswers.run())
    .then(() => {
      return storeValue(
        "originalAnswers",
        JSON.parse(JSON.stringify(appsmith.store.answers))
      );
    })
    .then(() => {
      showAlert("Answers saved", "success");
    });

})()
}}
